var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......땅속에 묻힌 걸 발굴하고 있었나 보네.","JPN":"……探し物は、地下に埋もれていたようなのよね。","ENG":"Looks like they've been excavating it from the ground.","TWN":"……看來他們是在挖那些埋在地下的東西。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러니 찾기 힘들 수밖에 없지.","JPN":"そりゃ、なかなか見つからないわけよ。","ENG":"No wonder it was so hard to find.","TWN":"所以我們要找到目標會非常困難。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"저 녀석들, 저런 건 대체 어떻게 찾아낸 거야? 무슨 두더지들인가?","JPN":"あいつら、いったいどうやって見つけたの？　まさかモグラなのかしら？","ENG":"How on earth did they even find it? Are they gophers or something?","TWN":"那些傢伙到底是怎麼找到那些東西的？他們是地鼠嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저건......","JPN":"あれは……","ENG":"Those are...","TWN":"那是……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"리플레이서 놈들이군. 바글바글한데?","JPN":"リプレイサーどもだな。うじゃうじゃいるぞ？","ENG":"Replacers. A whole lot of them at that...","TWN":"是克隆集團的混蛋們，他們人也太多了吧？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저 자식들이!","JPN":"あいつら！","ENG":"Those scumbags!","TWN":"那些傢伙！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"진정해, 애송아. 뒤집어엎는 건 언제든지 할 수 있으니까.","JPN":"落ち着け若造。突っこむことはいつでもできる。","ENG":"Easy now, rookie. We have plenty of time to take them down.","TWN":"冷靜點，小鬼，我們隨時都可以反轉戰局。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그보다 대리인. 그쪽에서 찾고 있다는 게 설마......","JPN":"それより代理人。そっちで探しているのはまさか……","ENG":"Anyway, Sylvia. Is the thing you're looking for...","TWN":"比起這個，代理人，他們在找的該不會是……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>로스트 쉽</color>이었나?","JPN":"<color=#ffd34c>ロストシップ</color>なのか？","ENG":"The <color=#ffd34c>Lost Ship</color>?","TWN":"<color=#ffd34c> 失落艦船</color>吧？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......호오.","JPN":"……へえ。","ENG":"Oh...","TWN":"哦……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"당신, 로스트 쉽에 대해 알고 있어?","JPN":"あなた、ロストシップのことを知ってるの？","ENG":"You know about the Lost Ship?","TWN":"妳也知道關於失落艦船的事情啊？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"신기하네. 이건 각국 정부에서도 극히 일부만 알고 있는 특급 기밀인데.","JPN":"不思議だわ。各国の政府でもごく一部だけが知っている最上級の機密情報なのに。","ENG":"Interesting... This is highly privileged information that only a select few government folks are privy to...","TWN":"真有趣。這是在各國政府間，也只有極少數的人才知道的特級機密呢。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어떻게 당신이 알고 있는 거지?","JPN":"どうしてあなたが知っているのかしら？","ENG":"How do you know about it?","TWN":"妳是怎麼知道的？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......베테랑의 경험이라고 해 두지.","JPN":"……ベテランの経験ということにしておこう。","ENG":"Let's just say that kind of knowledge comes with experience.","TWN":"……這就是老手的經驗了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"여기저기 구르다 보면 들려오는 이야기도 많아지는 법이니까.","JPN":"あちこち飛び回っていると、聞こえる話も増えるものだ。","ENG":"The more you get around, the more you hear.","TWN":"如果妳曾經到處流浪的話，妳就會聽到很多故事。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......흐음.","JPN":"……ふーん。","ENG":"Hmm...","TWN":"……嗯。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지금까지 보여 준 실력도 그렇고.......","JPN":"これまで見せてくれた実力からしても……","ENG":"After what you showed me on the battlefield...","TWN":"到目前為止，妳表現出來的實力也是。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"확실히 당신이 기대 이상의 베테랑이라는 점은 나도 인정할게.","JPN":"期待以上のベテランなのはアタシも認めるわ。","ENG":"I'll admit you do seem like quite the experienced veteran.","TWN":"我必須要承認，妳的確是一個超乎我期待的老手。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"둘이서 무슨 이야기를 하고 있는 거야?","JPN":"2人で何を話し込んでるの？","ENG":"What are you guys talking about?","TWN":"你們兩個在說什麼啊？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"로스트 쉽이 뭔데?","JPN":"ロストシップって、何？","ENG":"What's the Lost Ship?","TWN":"失落艦船又是什麼？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......가끔씩 세계 각지나 이면세계에서 발견되는 정체불명의 함선을 말하는 거예요. 미나 양.","JPN":"……世界各地やカウンターサイドで時々発見される正体不明の艦船のことです。","ENG":"It's a mysterious ship that is found in various parts of the world or in the Counterside, Mina.","TWN":"……是指偶爾在世界各地和異界發現的那些來歷不明的艦船，米娜小姐。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정체불명의 함선?","JPN":"正体不明の艦船？","ENG":"A mysterious ship?","TWN":"來歷不明的艦船？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"굉장히 오래된 것 같은데 누가 어디서 만들었는지......","JPN":"すごく古そうな見た目ですが、誰がどこで作ったのか……","ENG":"It appears to be extremely old, but no one knows who made it, and where...","TWN":"它們都非常古老，是誰、又是在哪裡製造的呢……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어떻게 거기 버려졌는지......","JPN":"どうしてそこに捨てられたのか……","ENG":"Or how it got lost there...","TWN":"又為什麼被遺棄在那裡……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무도 모르는, 미스터리한 함선이죠.","JPN":"誰も知らない、謎の艦船です。","ENG":"No one knows much about the ship. Hence the mysterious part.","TWN":"是誰都不知道，像謎一般的艦船。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런 걸 찾아서 어디에 쓰는데?","JPN":"そんなのを見つけて何に使うの？","ENG":"What's the point of finding something like that?","TWN":"那我們找這些艦船要做什麼？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그야 로스트 쉽에는 재미있는 것들이 실려 있는 경우가 많거든요.","JPN":"ロストシップでは面白いものが見つかることが多いんですよ。","ENG":"Because interesting things are often found on the Lost Ship.","TWN":"這個嘛，因為在失落艦船中有很多有趣的東西。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"예를 들어 고순도 이터니움 주괴가 박스째로 실려 있다거나......","JPN":"例えば、高純度のエタニウムの塊が箱ごと見つかったり……","ENG":"Such as boxes full of high-purity Eternium ingots...","TWN":"比如，大塊大塊的高純度永恆之金成箱裝在上面……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"도저히 오파츠로밖에는 부를 수 없는 기술 자료들이 들어 있다거나......","JPN":"オーパーツとしか言えない技術資料があったり……","ENG":"Or technological materials that can only be called out-of-place artifacts...","TWN":"又或是那些只能被稱作是歐帕茲的技術資料……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 다 소문뿐이긴 하지만요.","JPN":"まあ、すべて噂に過ぎないんですけどね。","ENG":"It's all hearsay, though.","TWN":"不過嘛，這些都只是傳言罷了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"듣기만 해서는 외계인 음모론이랑 별로 다른 것도 없는 것 같은데.","JPN":"聞いてる分には宇宙人の陰謀論とあまり変わらない気もするね。","ENG":"Sounds no different from UFO conspiracy theories...","TWN":"這聽起來好像和外星人之類的陰謀論沒什麼兩樣。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇긴 한데......","JPN":"まあ、そうなんですが……","ENG":"Indeed. However...","TWN":"是這樣沒錯啦……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"실비아 양 같은 분이 그걸 찾아서 여기까지 왔다는 건, 그냥 음모론으로 치부해 버릴 만한 이야기는 아니라는 거겠죠?","JPN":"シルビアさんみたいな方がそれを求めてここまで来たというのは、ただの陰謀論で済まされないからでしょうね。","ENG":"If someone like Sylvia came all the way here to find it, I'm not sure if we can just dismiss it as a conspiracy theory, you know?","TWN":"但如果是像希爾維亞小姐這樣的人都會來找的東西，那就不是用一句陰謀論能打發了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"흐음......","JPN":"うーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"좋아. 대충 이야기가 끝난 것 같군.","JPN":"よし、話はだいたいまとまったみたいだな。","ENG":"Great. Now that you're done talking...","TWN":"好了，談話也該告一段落了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"우리는 지금부터 리플레이서 놈들로부터 로스트 쉽을 탈환하러 간다.","JPN":"我々はこの後、リプレイサーどもからロストシップを奪い取る。","ENG":"We're going to go recover the Lost Ship from the Replacers.","TWN":"我們現在就從克隆集團手中奪回失落艦船吧。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다들 알고 있겠지만 겉모습과 달리 놈들은 융합체로 변신하여 강력한 힘을 낼 수 있다.","JPN":"みんなも知っての通り、見た目とは違い奴らは融合体に変身して強い力を発揮できる。","ENG":"As you all know, they may not look like much but they're capable of transforming into the more powerful hybriders.","TWN":"但大家都知道，那些傢伙和外表不同，他們可以變成融合體，使出強大的力量來對付我們。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"방심하지 말고 충분히 주의할 것.","JPN":"油断せず、十分注意するように。","ENG":"Stay frosty.","TWN":"所以不能大意，要隨時保持警戒。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이상!","JPN":"以上！","ENG":"Go!","TWN":"以上！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 아가씨.","JPN":"おい、嬢ちゃん。","ENG":"Hey, miss.","TWN":"喂，小姐！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":".....왜?","JPN":"……なんでしょう？","ENG":"Yes...?","TWN":"……什麼事？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저 안으로 들어가기 전에 서로 보험을 좀 들어두지 않겠나?","JPN":"あの中に入る前に、お互い保険をかけておかないか？","ENG":"How about we get some insurance before we go inside?","TWN":"在進去裡面之前，我們要不要給彼此一個保險？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"보험?","JPN":"保険？","ENG":"Insurance?","TWN":"保險？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 나도 아가씨들 사정을 굳이 캐묻고 싶지는 않지만......","JPN":"そうだ。　俺も嬢ちゃんたちの事情を詮索するつもりはないが……","ENG":"Yes. I don't mean to be all nosy...","TWN":"是啊，我不想刻意去問小姐你們的情況，但……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"지난번 사건을 보면 저 녀석들이 아가씨에게 아주 관심이 많은 것 같더군.","JPN":"この前の事件からして、あいつらは嬢ちゃんにとても興味があるようだ。","ENG":"But I noticed last time that those hybriders were particularly interested in you.","TWN":"從上次的事件來看，這些傢伙好像對小姐你們非常執著的樣子。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"확신할 순 없지만 이번 일......","JPN":"確信はできないが、今回のことは……","ENG":"I can't be certain, but...","TWN":"雖然我沒有確切的把握…… "},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"단순히 로스트 쉽에 대한 것으로 끝나지만은 않을 것 같은 예감이 들어.","JPN":"単にロストシップのことだけでは済まされない気がするんだ。","ENG":"I've got a feeling that the Lost Ship won't be the end of this mission.","TWN":"但我有預感，這件事不會只有失落艦船這麼簡單。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그건 베테랑 용병의 직감이야?","JPN":"それはベテラン傭兵としての直感ですか？","ENG":"Is that your gut feeling as a seasoned mercenary?","TWN":"這是老傭兵的直覺嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아니면 <color=#ffd34c>칩</color>에서 나온 정보를 분석한 건가?","JPN":"それとも、<color=#ffd34c>チップ</color>の情報を分析したんですか？","ENG":"Or did you get that from the <color=#ffd34c>chip</color> I gave you?","TWN":"還是分析了<color=#ffd34c>晶片</color>中的資料？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"둘 다라고 해 두지.","JPN":"両方、ということにしておくよ。","ENG":"Let's just say both.","TWN":"兩者都是吧。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어쨌든 대비를 해서 나쁠 건 없으니까.","JPN":"とにかく、備えあれば憂いなしだからな。","ENG":"Anyway, I don't think it's a bad idea to prepare for the worst.","TWN":"反正多做些準備也沒什麼不好的。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그래서? 어떤 보험을 들겠다는 거야?","JPN":"それで？　どんな保険をかけると言うんです？","ENG":"So? What are you suggesting?","TWN":"所以呢？是什麼樣的保險？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"간단해.","JPN":"とてもシンプルさ。","ENG":"It's simple.","TWN":"其實很簡單。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"맛있고 건강에 좋은 이 알약을 하나씩 나눠 먹는 거지.","JPN":"おいしくて健康にも良いこのカプセルを、お互い1つずつ飲むんだ。","ENG":"Let's each take this tasty and healthy little pill.","TWN":"妳把這些好吃又健康的藥錠分著吃掉吧。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......성분이 뭔데?","JPN":"……成分は？","ENG":"...What's in it?","TWN":"……成分是什麼？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"겉은 평범한 비타민제야.","JPN":"表向きには、普通のビタミン剤だ。","ENG":"From the outside, it just looks like an ordinary vitamin.","TWN":"外表看起來是普通的維他命。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......속은?","JPN":"……中身は？","ENG":"...And on the inside?","TWN":"……那裡面呢？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그건 좀 더 재미있는 거지......","JPN":"そりゃ、もっと面白いものさ……","ENG":"Something a bit more interesting...","TWN":"是比維他命更有趣的……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};